call_count = 0
@retry(max_retries=3, delay=0)
def flaky():
    global call_count
    call_count += 1
    if call_count < 3:
        raise ValueError('fail')
    return 'ok'
assert flaky() == 'ok'
assert call_count == 3

@retry(max_retries=2, delay=0)
def always_fail():
    raise RuntimeError('boom')
try:
    always_fail()
    assert False, 'should have raised'
except RuntimeError as e:
    assert str(e) == 'boom'

@retry(max_retries=1, delay=0)
def instant_ok():
    return 42
assert instant_ok() == 42
